                @* Compact Mode *@
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_editCompactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
