    font-weight: 600;
}

.nav-icon {
    font-size: 1.1rem;
}

/* ─── Content Area ─── */

.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 900px;
    position: relative;
}

.section-panel {
    animation: fadeIn 0.2s ease;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(6px); }
    to   { opacity: 1; transform: translateY(0); }
}

.section-heading {
    font-weight: 700;
    margin-bottom: 0.25rem;
}

/* ─── Toast ─── */

.toast-banner {
    display: flex;
    align-items: center;
    padding: 0.6rem 1rem;
    border-radius: 0.375rem;
    margin-bottom: 1.25rem;
    font-size: 0.9rem;
    font-weight: 500;
