toolArgs.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_274c08a4b0c7404cbd7fa2624eae1edf.Models
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => ActiveSection = section.Key">
                        <span class="nav-icon">@section.Value.Icon</span>
                        @section.Value.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @* Toast message *@
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="toast-banner @(_toastIsError ? "toast-error" : "toast-success")">
                    @_toastMessage
                    <button class="btn-close btn-close-sm ms-2" @onclick="() => _toastMessage = null"></button>
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfile()
                    break;
                case "notifications":
                    @RenderNotifications()
                    break;
                case "security":
                    @RenderSecurity()
                    break;
                case "appearance":
                    @RenderAppearance()
                    break;
            }
        }
    </div>
</div>

@* ──────────── Profile Section ──────────── *@

@{ RenderFragment RenderProfile() =>
    @<div class="section-panel">
        <h4 class="section-heading">Profile</h4>
        <p class="text-muted">Manage your public profile information.</p>
        <hr />

        <div class="row g-4">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input class="form-control" @bind="_editDisplayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_editEmail" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_editBio"></textarea>
                </div>
            </div>
            <div class="col-md-4">
                <label class="form-label">Avatar Preview</label>
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_editAvatarUrl))
                    {
                        <img src="@_editAvatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">No Avatar</div>
                    }
                </div>
                <div class="mt-2">
                    <label class="form-label">Avatar URL</label>
                    <input class="form-control form-control-sm" @bind="_editAvatarUrl" />
                </div>
            </div>
        </div>

        <div class="mt-4 d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
        </div>
    </div>;
}

@* ──────────── Notifications Section ──────────── *@

@{ RenderFragment RenderNotifications() =>
    @<div class="section-panel">
        <h4 class="section-heading">Notifications</h4>
        <p class="text-muted">Control how and when you receive notifications.</p>
        <hr />

        <div class="mb-4">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_editEmailNotif" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_editPushNotif" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_editWeeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <h6>Muted Channels</h6>
        <p class="text-muted small">Uncheck a channel to unmute it.</p>
        <div class="channel-list mb-4">
            @if (_allChannels is not null)
            {
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="ch-@ch"
                               checked="@_editMutedChannels.Contains(ch)"
                               @onchange="e => ToggleMutedChannel(ch, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="ch-@ch">#@ch</label>
                    </div>
                }
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Preferences
        </button>
    </div>;
}

@* ──────────── Security Section ──────────── *@

@{ RenderFragment RenderSecurity() =>
    @<div class="section-panel">
        <h4 class="section-heading">Security</h4>
        <p class="text-muted">Manage your password, two-factor authentication, and sessions.</p>
        <hr />

        @* Change Password *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 role="button" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Update Password
                    </button>
                    @if (_securitySettings?.LastPasswordChange is not null)
                    {
                        <small class="text-muted ms-3">
                            Last changed: @_securitySettings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                        </small>
                    }
                </div>
            }
        </div>

        @* Two-Factor Authentication *@
        <div class="card mb-4">
            <div class="card-body d-flex align-items-center justify-content-between">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <span class="badge ms-2 @(_editTwoFactor ? "bg-success" : "bg-secondary")">
                        @(_editTwoFactor ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch mb-0">
                    <input class="form-check-input" type="checkbox" id="twoFactor" @bind="_editTwoFactor" />
                </div>
            </div>
        </div>

        @* Active Sessions *@
        <h6>Active Sessions</h6>
        @if (_securitySettings?.Sessions is { Count: > 0 })
        {
            <div class="table-responsive">
                <table class="table table-hover align-middle">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _securitySettings.Sessions)
                        {
                            var s = session;
                            <tr>
                                <td>@s.Device</td>
                                <td>@s.Location</td>
                                <td>@FormatLastActive(s.LastActive)</td>
                                <td>
                                    @if (s.Id != _securitySettings.Sessions[0].Id)
                                    {
                                        @if (_confirmRevokeId == s.Id)
                                        {
                                            <span class="me-2 text-danger small">Revoke this session?</span>
                                            <button class="btn btn-danger btn-sm me-1" @onclick="() => RevokeSession(s.Id)">
                                                Yes
                                            </button>
                                            <button class="btn btn-outline-secondary btn-sm" @onclick="() => _confirmRevokeId = null">
                                                No
                                            </button>
                                        }
                                        else
                                        {
                                            <button class="btn btn-outline-danger btn-sm" @onclick="() => _confirmRevokeId = s.Id">
                                                Revoke
                                            </button>
                                        }
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
        else
        {
            <p class="text-muted">No active sessions.</p>
        }
    </div>;
}

@* ──────────── Appearance Section ──────────── *@

@{ RenderFragment RenderAppearance() =>
    @<div class="section-panel">
        <h4 class="section-heading">Appearance</h4>
        <p class="text-muted">Customize the look and feel of the application.</p>
        <hr />

        <div class="row g-4">
            <div class="col-md-6">
                @* Theme *@
                <div class="mb-4">
                    <label class="form-label fw-semibold">Theme</label>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        var t = theme;
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme" id="theme-@t"
                                   value="@t" checked="@(_editTheme == t)"
                                   @onchange="() => _editTheme = t" />
                            <label class="form-check-label" for="theme-@t">@t</label>
                        </div>
                    }
                </div>

                @* Font Size *@
                <div class="mb-4">
                    <label class="form-label fw-semibold">Font Size</label>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        var sz = size;
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize" id="fs-@sz"
                                   value="@sz" checked="@(_editFontSize == sz)"
                                   @onchange="() => _editFontSize = sz" />
                            <label class="form-check-label" for="fs-@sz">@sz</label>
                        </div>
                    }
                </div>

                @* Language *@
                <div class="mb-4">
                    <label class="form-label fw-semibold">Language</label>
                    <select class="form-select" @bind="_editLanguage">
                        <option value="English">English</option>
                        <option value="Spanish">Spanish</option>
                        <option value="French">French</option>
                        <option value="German">German</option>
                        <option value="Japanese">Japanese</option>
                        <option value="Chinese">Chinese</option>
                    </select>
                </div>

                @* Compact Mode *@
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_editCompactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            @* Live Preview *@
            <div class="col-md-6">
                <label class="form-label fw-semibold">Live Preview</label>
                <div class="preview-box @GetPreviewClasses()">
                    <div class="preview-header">My Application</div>
                    <div class="preview-body">
                        <p>This is a preview of your selected appearance settings.</p>
                        <div class="d-flex gap-2 mb-2">
                            <button class="btn btn-sm btn-primary">Primary</button>
                            <button class="btn btn-sm btn-secondary">Secondary</button>
                        </div>
                        <div class="preview-card">
                            <strong>Sample Card</strong>
                            <p class="mb-0 mt-1">Content looks like this with your current settings.</p>
                        </div>
                    </div>
                    <div class="preview-footer">
                        Theme: @_editTheme · Font: @_editFontSize · Lang: @_editLanguage · Compact: @(_editCompactMode ? "On" : "Off")
                    </div>
                </div>
            </div>
        </div>

        <div class="mt-4">
            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save
            </button>
        </div>
    </div>;
}

@code {
    // ─── Navigation ───
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🔒"),
        ["appearance"] = ("Appearance", "🎨")
    };

    // ─── Toast ───
    private string? _toastMessage;
    private bool _toastIsError;

    // ─── Saving indicator ───
    private bool _saving;

    // ─── Profile state ───
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editAvatarUrl = "";
    private string _editBio = "";

    // ─── Notifications state ───
    private bool _editEmailNotif;
    private bool _editPushNotif;
    private bool _editWeeklyDigest;
    private HashSet<string> _editMutedChannels = [];
    private List<string> _allChannels = [];

    // ─── Security state ───
    private SecuritySettings? _securitySettings;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _editTwoFactor;
    private string? _confirmRevokeId;

    // ─── Appearance state ───
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = profileTask.Result;
        PopulateProfileFields(_savedProfile);

        // Notifications
        var notif = notifTask.Result;
        _editEmailNotif = notif.EmailNotifications;
        _editPushNotif = notif.PushNotifications;
        _editWeeklyDigest = notif.WeeklyDigest;
        _allChannels = new List<string>(notif.MutedChannels);
        _editMutedChannels = new HashSet<string>(notif.MutedChannels);

        // Security
        _securitySettings = securityTask.Result;
        _editTwoFactor = _securitySettings.TwoFactorEnabled;

        // Appearance
        var app = appearanceTask.Result;
        _editTheme = app.Theme;
        _editFontSize = app.FontSize;
        _editLanguage = app.Language;
        _editCompactMode = app.CompactMode;

        _loading = false;
    }

    // ─── Profile helpers ───

    private void PopulateProfileFields(UserProfile p)
    {
        _editDisplayName = p.DisplayName;
        _editEmail = p.Email;
        _editAvatarUrl = p.AvatarUrl;
        _editBio = p.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        var profile = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            PopulateProfileFields(_savedProfile);
            ShowToast("Changes discarded.");
        }
    }

    // ─── Notifications helpers ───

    private void ToggleMutedChannel(string channel, bool isMuted)
    {
        if (isMuted)
            _editMutedChannels.Add(channel);
        else
            _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var prefs = new NotificationPrefs(_editEmailNotif, _editPushNotif, _editWeeklyDigest, _editMutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        ShowToast("Notification preferences saved.");
    }

    // ─── Security helpers ───

    private async Task UpdatePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _passwordError = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _saving = false;
        ShowToast("Password updated successfully.");
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _confirmRevokeId = null;
        ShowToast("Session revoked.");
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    // ─── Appearance helpers ───

    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        ShowToast("Appearance settings saved.");
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_editTheme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(_editFontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-sm",
            "large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_editCompactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    // ─── Toast ───

    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _ = DismissToastAfterDelay();
    }

    private async Task DismissToastAfterDelay()
    {
        await Task.Delay(3000);
        _toastMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}
